solution: ```class Solution {
    public int kthFactor(int n, int k) {
        int count = 0;
        for (int i = 1; i * i <= n; ++i) {
            if (n % i == 0) {
                ++count;
                if (count == k) return i;
            }
        }
        int upperStart = (int) Math.sqrt(n);
        if (upperStart * upperStart == n) --upperStart;
        for (int i = upperStart; i >= 1; --i) {
            if (n % i == 0) {
                ++count;
                if (count == k) return n / i;
            }
        }
        return -1;
    }
}
```
